solutions.javascript:
// Corrected solution
function validateComposeConfig(config) {
  const services = config.match(/services:(.*?)expose/g)[0].match(/services:(.*?)ports/g)[0];
  const exposedPorts = services.substring(services.indexOf('ports:')).split(/[,-]/).map(port => port.trim());
  const excludePorts = config.match(/expose:(.*?)networks/g)[0].split(/[,-]/).map(port => port.trim());
  const uniquePorts = new Set();
  for (const port of exposedPorts) {
    if (excludePorts.includes(port)) {
      return false;
    }
    uniquePorts.add(port);
  }
  return true;
}

