class Solution:
    def validate_compose_config(self, config) -> bool:
        services = config.split('services:')[1].split('expose:')[0].split('ports:')[1]
        exposedPorts = services.split('depends_on:')[0].split('environment:')[0].split(/[,-]/)
        excludePorts = config.split('expose:')[1].split('networks:')[0].split(/[,-]/)
        uniquePorts = set()
        for port in exposedPorts:
            if port in excludePorts:
                return False
            uniquePorts.add(port)
        return True
